const email = $input.first().json;

// Gmail Trigger v1.2 renvoie les champs en MAJUSCULE : From, To, Subject
// On normalise pour gerer les deux formats
const fromRaw = email.from || email.From || '';
const toRaw = email.to || email.To || '';
const subjectRaw = email.subject || email.Subject || '(sans objet)';
const dateRaw = email.date || email.Date || email.internalDate || new Date().toISOString();
const snippetRaw = email.snippet || email.Snippet || '';
const textRaw = email.textPlain || email.TextPlain || email.text || snippetRaw || '';

// Extraire les adresses email de maniere robuste
function extractEmail(field) {
  if (!field) return '';
  if (typeof field === 'string') return field;
  if (field.text) return field.text;
  if (field.value && Array.isArray(field.value)) return field.value.map(v => v.address || v.name || '').join(', ');
  if (Array.isArray(field)) return field.map(f => typeof f === 'string' ? f : (f.address || f.text || '')).join(', ');
  if (field.address) return field.address;
  return JSON.stringify(field);
}

const fromStr = extractEmail(fromRaw);
const toStr = extractEmail(toRaw);

console.log('[02] fromStr:', fromStr);
console.log('[02] toStr:', toStr);

// ═══ FILTRE ANTI-BOUCLE ═══
// Exclure les emails envoyes PAR le systeme (evite de traiter nos propres reponses)
const SYSTEM_ADDRESSES = ['direction@talosprimes.com', 'noreply@talosprimes.com', 'contact@talosprimes.com'];
const fromLower = fromStr.toLowerCase();
const isFromSystem = SYSTEM_ADDRESSES.some(addr => fromLower.includes(addr));

// Aussi verifier le label SENT
const labels = email.labelIds || [];
const isSentMail = labels.includes('SENT') || labels.includes('SENT_MAIL');

if (isFromSystem || isSentMail) {
  console.log('[02] SKIP: email envoye par le systeme (from=' + fromStr + ', labels=' + labels.join(',') + ')');
  return [{ json: { skip: true, reason: 'Email envoye par le systeme — ignore pour eviter boucle' } }];
}

// Chercher le tenantId dans toutes les adresses
const TENANT_MAP = {
  'direction@talosprimes.com': 'efbf3d9e-6ccc-44a3-ad41-dc4093ecc227'
};

const allAddresses = (fromStr + ' ' + toStr + ' ' + JSON.stringify(email)).toLowerCase();

let tenantId = null;
for (const [addr, tid] of Object.entries(TENANT_MAP)) {
  if (allAddresses.includes(addr.toLowerCase())) { tenantId = tid; break; }
}

if (!tenantId) {
  throw new Error('[02] TENANT_MAP: aucun match. From=' + fromStr + ' To=' + toStr + '. Ajouter l adresse dans TENANT_MAP.');
}

return [{ json: {
  id: email.id || email.messageId || null,
  threadId: email.threadId || null,
  from: fromStr,
  to: toStr,
  subject: subjectRaw,
  date: dateRaw,
  snippet: snippetRaw,
  textPlain: textRaw.substring(0, 1000),
  labels: email.labelIds || [],
  hasAttachments: (email.attachments || []).length > 0,
  tenantId: tenantId,
  action: 'received'
} }];

