const agentOutput = $input.first().json;
const text = agentOutput.output || agentOutput.text || JSON.stringify(agentOutput);
const emailData = $('02. Traiter email').first().json;

console.log('[04] emailData.tenantId:', emailData.tenantId);
console.log('[04] emailData.from:', emailData.from);
console.log('[04] emailData.to:', emailData.to);

// Verifier que tenantId est valide
if (!emailData.tenantId || emailData.tenantId === 'null') {
  throw new Error('tenantId est null — le TENANT_MAP n a pas matche. Verifier les logs du node 02.');
}

// Extraire le bloc JSON de la sortie de l'agent
let agentData = {};
const jsonBlockMatch = text.match(/```json\s*([\s\S]*?)\s*```/);
if (jsonBlockMatch) {
  try { agentData = JSON.parse(jsonBlockMatch[1]); } catch (e) {
    console.warn('[04] Erreur parse JSON block:', e.message);
  }
}
if (Object.keys(agentData).length === 0) {
  const rawMatch = text.match(/\{[\s\S]*"classification"[\s\S]*\}/);
  if (rawMatch) {
    try { agentData = JSON.parse(rawMatch[0]); } catch (e) {
      console.warn('[04] Erreur parse raw JSON:', e.message);
    }
  }
}

console.log('[04] agentData extrait:', JSON.stringify(agentData).substring(0, 300));

const classification = agentData.classification || { categorie: 'autre', priorite: 'moyenne', intention: 'autre', confiance: 0 };

return [{ json: {
  tenantId: emailData.tenantId,
  emailId: emailData.id || null,
  threadId: emailData.threadId || null,
  fromAddress: emailData.from || '',
  toAddress: emailData.to || '',
  subject: emailData.subject || '(sans objet)',
  bodyPreview: (emailData.snippet || emailData.textPlain || '').substring(0, 500),
  hasAttachments: emailData.hasAttachments || false,
  classification: JSON.stringify(classification),
  action: agentData.action || 'classified',
  replySubject: agentData.replySubject || null,
  replyBody: agentData.replyBody || null,
  replyHtml: agentData.replyHtml || null,
  replyConfidence: Number(agentData.replyConfidence) || 0,
  replyAction: agentData.replyAction || 'queue_human'
} }];
